import SwiftUI

public struct SkeletonShimmerView: View {
  @State private var shimmerOffset: CGFloat = -160

  public init() {}

  public var body: some View {
    VStack(alignment: .leading, spacing: 14) {
      shimmerBlock(width: 180, height: 18)
      shimmerBlock(width: nil, height: 12)
      shimmerBlock(width: 220, height: 12)
      HStack(spacing: 12) {
        shimmerBlock(width: 84, height: 28)
        shimmerBlock(width: 96, height: 28)
      }
    }
    .padding(20)
    .background(
      RoundedRectangle(cornerRadius: 20, style: .continuous)
        .fill(Color(.secondarySystemBackground))
    )
  }

  private func shimmerBlock(width: CGFloat?, height: CGFloat) -> some View {
    RoundedRectangle(cornerRadius: height / 2, style: .continuous)
      .fill(Color(.systemGray5))
      .frame(maxWidth: width == nil ? .infinity : width, minHeight: height, maxHeight: height)
      .overlay {
        GeometryReader { proxy in
          LinearGradient(
            colors: [.clear, .white.opacity(0.55), .clear],
            startPoint: .leading,
            endPoint: .trailing
          )
          .frame(width: proxy.size.width * 0.45)
          .offset(x: shimmerOffset)
        }
        .mask(
          RoundedRectangle(cornerRadius: height / 2, style: .continuous)
            .frame(height: height)
        )
      }
      .onAppear {
        withAnimation(.linear(duration: 1.1).repeatForever(autoreverses: false)) {
          shimmerOffset = 220
        }
      }
  }
}

import SwiftUI

public struct LikeButtonBounce: View {
  @State private var isLiked: Bool
  @State private var scale: CGFloat = 1
  public let baseCount: Int

  public init(baseCount: Int = 128, isInitiallyLiked: Bool = false) {
    self.baseCount = baseCount
    _isLiked = State(initialValue: isInitiallyLiked)
  }

  public var body: some View {
    Button {
      isLiked.toggle()
      scale = 0.82
      withAnimation(.spring(response: 0.28, dampingFraction: 0.45)) {
        scale = 1
      }
    } label: {
      HStack(spacing: 10) {
        Image(systemName: isLiked ? "heart.fill" : "heart")
          .foregroundStyle(isLiked ? .pink : .secondary)
          .scaleEffect(scale)
        Text("\(baseCount + (isLiked ? 1 : 0))")
          .font(.headline.weight(.semibold))
      }
      .padding(.horizontal, 16)
      .padding(.vertical, 12)
      .background(
        Capsule(style: .continuous)
          .fill(Color(.secondarySystemBackground))
      )
    }
    .buttonStyle(.plain)
  }
}

import SwiftUI

public struct UniversalCardContainerView<Content: View>: View {
  public let eyebrow: String
  public let title: String
  public let summary: String
  private let content: Content

  public init(
    eyebrow: String,
    title: String,
    summary: String,
    @ViewBuilder content: () -> Content
  ) {
    self.eyebrow = eyebrow
    self.title = title
    self.summary = summary
    self.content = content()
  }

  public var body: some View {
    VStack(alignment: .leading, spacing: 16) {
      VStack(alignment: .leading, spacing: 8) {
        Text(eyebrow.uppercased())
          .font(.caption.weight(.semibold))
          .foregroundStyle(.secondary)
        Text(title)
          .font(.title3.weight(.semibold))
        Text(summary)
          .font(.subheadline)
          .foregroundStyle(.secondary)
      }

      Divider()

      content
        .foregroundStyle(.secondary)
    }
    .padding(20)
    .background(
      RoundedRectangle(cornerRadius: 22, style: .continuous)
        .fill(Color(.secondarySystemBackground))
    )
    .overlay(
      RoundedRectangle(cornerRadius: 22, style: .continuous)
        .strokeBorder(.quaternary, lineWidth: 1)
    )
  }
}

