public struct SearchPageSkeletonView: View {
  public init() {}

  public var body: some View {
    VStack(alignment: .leading, spacing: 18) {
      RoundedRectangle(cornerRadius: 16, style: .continuous)
        .fill(Color(.secondarySystemBackground))
        .frame(height: 52)
        .overlay(alignment: .leading) {
          Label("Search snippets, prompts, or patterns", systemImage: "magnifyingglass")
            .foregroundStyle(.secondary)
            .padding(.horizontal, 16)
        }

      section(title: "Recent searches", widths: [110, 144, 96])
      section(title: "Hot tags", widths: [92, 126, 84, 118])
    }
  }

  private func section(title: String, widths: [CGFloat]) -> some View {
    VStack(alignment: .leading, spacing: 12) {
      Text(title)
        .font(.headline.weight(.semibold))

      FlexibleChipRow(widths: widths)
    }
  }
}

private struct FlexibleChipRow: View {
  let widths: [CGFloat]

  var body: some View {
    let columns = [GridItem(.adaptive(minimum: 84), spacing: 10, alignment: .leading)]

    LazyVGrid(columns: columns, alignment: .leading, spacing: 10) {
      ForEach(Array(widths.enumerated()), id: \.offset) { _, width in
        Capsule(style: .continuous)
          .fill(Color(.secondarySystemBackground))
          .frame(width: width, height: 30)
      }
    }
  }
}

import SwiftUI

public enum LoadableState {
  case loading
  case empty(message: String)
  case error(message: String)
  case content
}

public struct LoadableViewStates<Content: View>: View {
  public let state: LoadableState
  private let content: Content

  public init(state: LoadableState, @ViewBuilder content: () -> Content) {
    self.state = state
    self.content = content()
  }

  public var body: some View {
    switch state {
    case .loading:
      ProgressView("Loading snippet...")
        .frame(maxWidth: .infinity, minHeight: 140)
    case let .empty(message):
      messageCard(icon: "tray", message: message)
    case let .error(message):
      messageCard(icon: "exclamationmark.triangle", message: message)
    case .content:
      content
    }
  }

  private func messageCard(icon: String, message: String) -> some View {
    VStack(spacing: 10) {
      Image(systemName: icon)
        .font(.title2)
      Text(message)
        .multilineTextAlignment(.center)
        .foregroundStyle(.secondary)
    }
    .frame(maxWidth: .infinity, minHeight: 140)
  }
}

